function Button({ label, variant = 'primary', onClick }) {
  const [isPressed, setIsPressed] = useState(false);

  return (
    <button
      className={`button button--${variant} ${isPressed ? 'button--pressed' : ''}`}
      onClick={() => {
        setIsPressed(true);
        onClick?.();
        setTimeout(() => setIsPressed(false), 150);
      }}
    >
      {label}
    </button>
  );
}
